// Column: builds ALL rows immediately, even off-screen ones
Column {
    forecastList.forEach { day -> ForecastRow(day) }
}

// LazyColumn: builds rows only as they scroll into view
LazyColumn {
    items(forecastList) { day -> ForecastRow(day) }
}

fun calculateAverage(temps: List<Int>): Int {
    return temps.sum() / temps.size
}

@Composable
fun AverageTempLabel(temps: List<Int>) {
    Text("Average: ${calculateAverage(temps)}°")
}

